#!/usr/bin/env bun
/**
 * tool-call-counter.ts — Track tool calls per session with auto-compact
 *
 * PostToolUse hook: increments counter in out/tool-call-count.
 * Called with --check from Stop hook: triggers auto-compact at threshold.
 * Called with --reset from SessionStart hook: resets counter.
 *
 * Threshold: 75 tool calls → auto-compact for quality.
 * Counter resets after compact trigger so the cycle repeats.
 */

import { readFileSync, writeFileSync, mkdirSync } from "fs";
import { join } from "path";
import { fromRoot } from "../../src/libs/paths.js";

const COMPACT_THRESHOLD = 75;

const outDir = fromRoot("out");
const counterFile = join(outDir, "tool-call-count");

function getCount(): number {
  try {
    return parseInt(readFileSync(counterFile, "utf-8").trim(), 10) || 0;
  } catch {
    return 0;
  }
}

function setCount(n: number): void {
  mkdirSync(outDir, { recursive: true });
  writeFileSync(counterFile, String(n), "utf-8");
}

const mode = process.argv[2];

if (mode === "--reset") {
  setCount(0);
  process.exit(0);
}

if (mode === "--check") {
  const count = getCount();
  if (count >= COMPACT_THRESHOLD) {
    process.stderr.write(
      `[auto-compact] ${count} tool calls reached. Compact now to maintain response quality. Run /compact then continue.`
    );
    // Reset counter so the cycle repeats after compact
    setCount(0);
  }
  process.exit(0);
}

// Default: increment (PostToolUse mode)
const count = getCount() + 1;
setCount(count);
process.exit(0);

