#!/usr/bin/env bun
/**
 * pre-compact-save.ts — Save session state before context compaction
 *
 * PreCompact hook: saves critical working state to out/session-state.json
 * so it can survive compaction.
 *
 * The state file is informational — agents and skills can read it to
 * recover context after compaction. It's NOT automatically injected.
 */

import { readFileSync, writeFileSync, mkdirSync, existsSync } from "fs";
import { join } from "path";
import { fromRoot } from "../../src/libs/paths.js";

const outDir = fromRoot("out");
const stateFile = join(outDir, "session-state.json");
const counterFile = join(outDir, "tool-call-count");

mkdirSync(outDir, { recursive: true });

// Read tool call count
let toolCallCount = 0;
try {
  toolCallCount = parseInt(readFileSync(counterFile, "utf-8").trim(), 10) || 0;
} catch {}

// Read previous state if it exists (preserve accumulated data)
let previousState: Record<string, any> = {};
try {
  if (existsSync(stateFile)) {
    previousState = JSON.parse(readFileSync(stateFile, "utf-8"));
  }
} catch {}

// Build state snapshot
const state = {
  timestamp: new Date().toISOString(),
  toolCallCount,
  compactionCount: (previousState.compactionCount || 0) + 1,
  previousCompaction: previousState.timestamp || null,
  note: "Context was compacted. Check task list and recent git log for current work state.",
};

writeFileSync(stateFile, JSON.stringify(state, null, 2), "utf-8");

process.stderr.write(
  `[pre-compact] Session state saved (${toolCallCount} tool calls, compaction #${state.compactionCount}). State: out/session-state.json`
);

process.exit(0);

