1	/**
2	 * brain/raw.ts — Sync and insert logic for raw context files
3	 *
4	 * Handles indexing of vault/studio/memory/raw/ files into brain.db.
5	 * Separate from syncMemories() — raw files are NOT agent memory files.
6	 *
7	 * Tables written: raw_files, raw_chunks, raw_fts (via trigger), vec_raw, sync_meta
8	 *
9	 * Per-message indexing: one raw_chunks row for summaryBody + one row per message.
10	 * This enables --search-raw to return specific messages rather than entire session dumps.
11	 */
12	
13	import { readdirSync, readFileSync, existsSync } from "fs";
14	import { join, relative } from "path";
15	import { createHash } from "crypto";
16	import { fromRoot } from "../paths.js";
17	import { getRawDb } from "../sqlite.js";
18	import { embedBatch, vectorToBuffer, EMBEDDING_CONFIG } from "../embeddings.js";
19	import type { CapturedMessage } from "../raw.js";
20	
21	const VAULT_STUDIO = fromRoot("vault", "studio");
22	const RAW_DIR = join(VAULT_STUDIO, "memory", "raw");
23	
24	// ─── Types ────────────────────────────────────────────────────
25	
26	export interface RawSyncResult {
27	  filesProcessed: number;
28	  chunksCreated: number;
29	  chunksEmbedded: number;
30	  chunksFailed: number;
31	}
32	
33	interface RawJsonFile {
34	  ts: number;
35	  date: string;
36	  sessionId?: string | null;
37	  agents: string[];
38	  skill?: string | null;
39	  tags?: string[];
40	  summary?: string | null;
41	  summaryBody?: string | null;
42	  messages: CapturedMessage[];
43	}
44	
45	// ─── Helpers ─────────────────────────────────────────────────
46	
47	function hashFile(content: string): string {
48	  return createHash("sha256").update(content).digest("hex").slice(0, 16);
49	}
50	
51	function now(): string {
52	  return new Date().toISOString();
53	}
54	
55	/** Read flat .json files from the raw directory (non-recursive) */
56	function findRawFiles(): string[] {
57	  if (!existsSync(RAW_DIR)) return [];
58	  return readdirSync(RAW_DIR, { withFileTypes: true })
59	    .filter(e => e.isFile() && e.name.endsWith(".json"))
60	    .map(e => join(RAW_DIR, e.name));
61	}
62	
63	/**
64	 * Serialize a CapturedMessage to a search-friendly string for FTS/embedding.
65	 */
66	function messageToSearchText(msg: CapturedMessage): string {
67	  if (msg.type === "tool_use") {
68	    const argsStr = msg.args ? JSON.stringify(msg.args) : "{}";
69	    return `tool_use: ${msg.tool ?? "unknown"} — ${argsStr}`;
70	  }
71	  if (msg.role === "tool_result") {
72	    return `tool_result: ${msg.tool ?? "unknown"} — ${msg.content ?? ""}`;
73	  }
74	  // text and thinking
75	  return msg.content ?? "";
76	}
77	
78	/**
79	 * Label for raw_chunks.section_name — gives search results context.
80	 */
81	function messageSectionName(msg: CapturedMessage, index: number): string {
82	  const role = msg.role;
83	  if (msg.type === "tool_use") return `msg-${index}-tool_use-${msg.tool ?? "unknown"}`;
84	  if (role === "tool_result") return `msg-${index}-tool_result-${msg.tool ?? "unknown"}`;
85	  if (msg.type === "thinking") return `msg-${index}-thinking`;
86	  return `msg-${index}-${role}`;
87	}
88	
89	// ─── Core ─────────────────────────────────────────────────────
90	
91	/**
92	 * Insert a single raw .json file into brain.db with per-message chunking.
93	 *
94	 * 1. JSON.parse the file
95	 * 2. Upsert raw_files (ts, date, agents, skill, tags, summary)
96	 * 3. Delete old chunks for this file
97	 * 4. Insert one chunk for summaryBody (semantic anchor)
98	 * 5. Insert one chunk per message
99	 * 6. Batch embed all chunks
100	 * 7. Update sync_meta
101	 */
102	export async function insertRawFile(filePath: string, opts?: { skipEmbed?: boolean }): Promise<{
103	  rawId: number;
104	  chunksCreated: number;
105	  chunksEmbedded: number;
106	}> {
107	  const rawDb = getRawDb();
108	  const fileContent = readFileSync(filePath, "utf-8");
109	  const hash = hashFile(fileContent);
110	  const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");
111	  const ts = now();
112	
113	  // Check if already indexed and unchanged
114	  const existing = rawDb.prepare("SELECT id, file_hash FROM raw_files WHERE source_path = ?").get(sourcePath) as { id: number; file_hash: string } | null;
115	  if (existing && existing.file_hash === hash) {
116	    return { rawId: existing.id, chunksCreated: 0, chunksEmbedded: 0 };
117	  }
118	
119	  let parsed: RawJsonFile;
120	  try {
121	    parsed = JSON.parse(fileContent) as RawJsonFile;
122	  } catch {
123	    throw new Error(`Failed to parse raw JSON file: ${filePath}`);
124	  }
125	
126	  const agents = JSON.stringify(Array.isArray(parsed.agents) ? parsed.agents : []);
127	  const skill = parsed.skill ?? null;
128	  const tagsStr = Array.isArray(parsed.tags) ? parsed.tags.join(", ") : null;
129	  const summary = parsed.summary ?? null;
130	  const fileTs = typeof parsed.ts === "number" ? parsed.ts : 0;
131	  const date = parsed.date ?? "";
132	
133	  // Upsert raw_files
134	  rawDb.prepare(`
135	    INSERT INTO raw_files (ts, date, agents, skill, tags, summary, source_path, file_hash, created_at)
136	    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
137	    ON CONFLICT(source_path) DO UPDATE SET
138	      ts=excluded.ts, date=excluded.date, agents=excluded.agents,
139	      skill=excluded.skill, tags=excluded.tags, summary=excluded.summary,
140	      file_hash=excluded.file_hash
141	  `).run(fileTs, date, agents, skill, tagsStr, summary, sourcePath, hash, ts);
142	
143	  // Get raw_id (needed after upsert — lastInsertRowid is unreliable on conflict)
144	  const row = rawDb.prepare("SELECT id FROM raw_files WHERE source_path = ?").get(sourcePath) as { id: number };
145	  const rawId = row.id;
146	
147	  // Delete old chunks for this file (re-index case)
148	  const oldChunkIds = rawDb.prepare("SELECT id FROM raw_chunks WHERE raw_id = ?").all(rawId) as { id: number }[];
149	  if (oldChunkIds.length > 0) {
150	    rawDb.exec("DELETE FROM raw_chunks WHERE raw_id = ?", [rawId] as any);
151	    for (const { id } of oldChunkIds) {
152	      try { rawDb.exec("DELETE FROM vec_raw WHERE chunk_id = ?", [id] as any); } catch {}
153	    }
154	  }
155	
156	  const pendingEmbeds: { chunkId: number; content: string }[] = [];
157	  let chunksCreated = 0;
158	
159	  // Summary chunk — the semantic anchor for the whole session
160	  const summaryText = parsed.summaryBody ?? parsed.summary ?? "";
161	  if (summaryText.trim()) {
162	    const chunkResult = rawDb.prepare(`
163	      INSERT INTO raw_chunks (raw_id, section_name, content, line_start, line_end, token_count, file_hash, created_at, updated_at)
164	      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
165	    `).run(rawId, "summary", summaryText, 0, 0, Math.ceil(summaryText.length / 4), hash, ts, ts);
166	    const chunkId = Number(chunkResult.lastInsertRowid);
167	    pendingEmbeds.push({ chunkId, content: summaryText });
168	    chunksCreated++;
169	  }
170	
171	  // Per-message chunks
172	  const messages = Array.isArray(parsed.messages) ? parsed.messages : [];
173	  for (let i = 0; i < messages.length; i++) {
174	    const msg = messages[i];
175	    const searchText = messageToSearchText(msg);
176	    if (!searchText.trim()) continue;
177	
178	    const sectionName = messageSectionName(msg, i);
179	    // Store only searchText as content — FTS stays clean. Full message is recoverable
180	    // from the .json file using line_start (message index).
181	    const content = searchText;
182	
183	    const chunkResult = rawDb.prepare(`
184	      INSERT INTO raw_chunks (raw_id, section_name, content, line_start, line_end, token_count, file_hash, created_at, updated_at)
185	      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
186	    `).run(rawId, sectionName, content, i, i, Math.ceil(searchText.length / 4), hash, ts, ts);
187	    const chunkId = Number(chunkResult.lastInsertRowid);
188	    pendingEmbeds.push({ chunkId, content: searchText }); // embed the readable text, not the full JSON
189	    chunksCreated++;
190	  }
191	
192	  // Update sync_meta
193	  rawDb.exec(`
194	    INSERT INTO sync_meta (source_path, file_hash, table_name, synced_at)
195	    VALUES (?, ?, 'raw_files', ?)
196	    ON CONFLICT(source_path) DO UPDATE SET
197	      file_hash=excluded.file_hash, synced_at=excluded.synced_at
198	  `.trim(), [sourcePath, hash, ts] as any);
199	
200	  // Batch embed
201	  let chunksEmbedded = 0;
202	
203	  if (!opts?.skipEmbed && pendingEmbeds.length > 0) {
204	    const texts = pendingEmbeds.map(p => p.content);
205	    const embedResult = await embedBatch(texts, "brain-raw-sync");
206	    const embedTs = now();
207	
208	    for (let i = 0; i < pendingEmbeds.length; i++) {
209	      const embedding = embedResult.embeddings[i];
210	      if (embedding) {
211	        const buf = vectorToBuffer(embedding);
212	        rawDb.exec(
213	          "UPDATE raw_chunks SET embed_model = ?, embedded_at = ?, updated_at = ? WHERE id = ?",
214	          [EMBEDDING_CONFIG.model, embedTs, embedTs, pendingEmbeds[i].chunkId] as any
215	        );
216	        try {
217	          rawDb.exec(
218	            "INSERT INTO vec_raw(chunk_id, embedding) VALUES (?, ?)",
219	            [pendingEmbeds[i].chunkId, buf] as any
220	          );
221	        } catch {
222	          rawDb.exec(
223	            "UPDATE vec_raw SET embedding = ? WHERE chunk_id = ?",
224	            [buf, pendingEmbeds[i].chunkId] as any
225	          );
226	        }
227	        chunksEmbedded++;
228	      }
229	    }
230	  }
231	
232	  return { rawId, chunksCreated, chunksEmbedded };
233	}
234	
235	/**
236	 * Sync all raw files from vault/studio/memory/raw/ into brain.db.
237	 * Incremental: uses file_hash via sync_meta to skip unchanged files.
238	 *
239	 * @param opts.full - Rebuild all raw entries from scratch
240	 */
241	export async function syncRaw(opts?: { full?: boolean }): Promise<RawSyncResult> {
242	  const rawDb = getRawDb();
243	  const files = findRawFiles();
244	
245	  if (opts?.full) {
246	    rawDb.exec("DELETE FROM raw_chunks");
247	    rawDb.exec("DELETE FROM vec_raw");
248	    rawDb.exec("DELETE FROM raw_files");
249	    rawDb.exec("DELETE FROM sync_meta WHERE table_name = 'raw_files'");
250	  }
251	
252	  let filesProcessed = 0;
253	  let chunksCreated = 0;
254	  let chunksEmbedded = 0;
255	  let chunksFailed = 0;
256	
257	  for (const filePath of files) {
258	    const content = readFileSync(filePath, "utf-8");
259	    const hash = hashFile(content);
260	    const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");
261	
262	    // Skip unchanged files (incremental)
263	    const existing = rawDb.prepare("SELECT file_hash FROM sync_meta WHERE source_path = ?").get(sourcePath) as { file_hash: string } | null;
264	    if (existing && existing.file_hash === hash && !opts?.full) continue;
265	
266	    try {
267	      const result = await insertRawFile(filePath);
268	      chunksCreated += result.chunksCreated;
269	      chunksEmbedded += result.chunksEmbedded;
270	      filesProcessed++;
271	    } catch (err) {
272	      // Skip files that fail to parse — may be legacy .md files or corrupt
273	      chunksFailed++;
274	    }
275	  }
276	
277	  return { filesProcessed, chunksCreated, chunksEmbedded, chunksFailed };
278	}
279

