/**
 * brain/raw.ts — Sync and insert logic for raw context files
 *
 * Handles indexing of vault/studio/memory/raw/ files into brain.db.
 * Separate from syncMemories() — raw files are NOT agent memory files.
 *
 * Tables written: raw_files, raw_chunks, raw_fts (via trigger), vec_raw, sync_meta
 *
 * Per-message indexing: one raw_chunks row for summaryBody + one row per message.
 * This enables --search-raw to return specific messages rather than entire session dumps.
 */

import { readdirSync, readFileSync, existsSync } from "fs";
import { join, relative } from "path";
import { createHash } from "crypto";
import { fromRoot } from "../paths.js";
import { getRawDb } from "../sqlite.js";
import { embedBatch, vectorToBuffer, EMBEDDING_CONFIG } from "../embeddings.js";
import type { CapturedMessage } from "../raw.js";

const VAULT_STUDIO = fromRoot("vault", "studio");
const RAW_DIR = join(VAULT_STUDIO, "memory", "raw");

// ─── Types ────────────────────────────────────────────────────

export interface RawSyncResult {
  filesProcessed: number;
  chunksCreated: number;
  chunksEmbedded: number;
  chunksFailed: number;
}

interface RawJsonFile {
  ts: number;
  date: string;
  sessionId?: string | null;
  agents: string[];
  skill?: string | null;
  tags?: string[];
  summary?: string | null;
  summaryBody?: string | null;
  messages: CapturedMessage[];
}

// ─── Helpers ─────────────────────────────────────────────────

function hashFile(content: string): string {
  return createHash("sha256").update(content).digest("hex").slice(0, 16);
}

function now(): string {
  return new Date().toISOString();
}

/** Read flat .json files from the raw directory (non-recursive) */
function findRawFiles(): string[] {
  if (!existsSync(RAW_DIR)) return [];
  return readdirSync(RAW_DIR, { withFileTypes: true })
    .filter(e => e.isFile() && e.name.endsWith(".json"))
    .map(e => join(RAW_DIR, e.name));
}

/**
 * Serialize a CapturedMessage to a search-friendly string for FTS/embedding.
 */
function messageToSearchText(msg: CapturedMessage): string {
  if (msg.type === "tool_use") {
    const argsStr = msg.args ? JSON.stringify(msg.args) : "{}";
    return `tool_use: ${msg.tool ?? "unknown"} — ${argsStr}`;
  }
  if (msg.role === "tool_result") {
    return `tool_result: ${msg.tool ?? "unknown"} — ${msg.content ?? ""}`;
  }
  // text and thinking
  return msg.content ?? "";
}

/**
 * Label for raw_chunks.section_name — gives search results context.
 */
function messageSectionName(msg: CapturedMessage, index: number): string {
  const role = msg.role;
  if (msg.type === "tool_use") return `msg-${index}-tool_use-${msg.tool ?? "unknown"}`;
  if (role === "tool_result") return `msg-${index}-tool_result-${msg.tool ?? "unknown"}`;
  if (msg.type === "thinking") return `msg-${index}-thinking`;
  return `msg-${index}-${role}`;
}

// ─── Core ─────────────────────────────────────────────────────

/**
 * Insert a single raw .json file into brain.db with per-message chunking.
 *
 * 1. JSON.parse the file
 * 2. Upsert raw_files (ts, date, agents, skill, tags, summary)
 * 3. Delete old chunks for this file
 * 4. Insert one chunk for summaryBody (semantic anchor)
 * 5. Insert one chunk per message
 * 6. Batch embed all chunks
 * 7. Update sync_meta
 */
export async function insertRawFile(filePath: string, opts?: { skipEmbed?: boolean }): Promise<{
  rawId: number;
  chunksCreated: number;
  chunksEmbedded: number;
}> {
  const rawDb = getRawDb();
  const fileContent = readFileSync(filePath, "utf-8");
  const hash = hashFile(fileContent);
  const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");
  const ts = now();

  // Check if already indexed and unchanged
  const existing = rawDb.prepare("SELECT id, file_hash FROM raw_files WHERE source_path = ?").get(sourcePath) as { id: number; file_hash: string } | null;
  if (existing && existing.file_hash === hash) {
    return { rawId: existing.id, chunksCreated: 0, chunksEmbedded: 0 };
  }

  let parsed: RawJsonFile;
  try {
    parsed = JSON.parse(fileContent) as RawJsonFile;
  } catch {
    throw new Error(`Failed to parse raw JSON file: ${filePath}`);
  }

  const agents = JSON.stringify(Array.isArray(parsed.agents) ? parsed.agents : []);
  const skill = parsed.skill ?? null;
  const tagsStr = Array.isArray(parsed.tags) ? parsed.tags.join(", ") : null;
  const summary = parsed.summary ?? null;
  const fileTs = typeof parsed.ts === "number" ? parsed.ts : 0;
  const date = parsed.date ?? "";

  // Upsert raw_files
  rawDb.prepare(`
    INSERT INTO raw_files (ts, date, agents, skill, tags, summary, source_path, file_hash, created_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(source_path) DO UPDATE SET
      ts=excluded.ts, date=excluded.date, agents=excluded.agents,
      skill=excluded.skill, tags=excluded.tags, summary=excluded.summary,
      file_hash=excluded.file_hash
  `).run(fileTs, date, agents, skill, tagsStr, summary, sourcePath, hash, ts);

  // Get raw_id (needed after upsert — lastInsertRowid is unreliable on conflict)
  const row = rawDb.prepare("SELECT id FROM raw_files WHERE source_path = ?").get(sourcePath) as { id: number };
  const rawId = row.id;

  // Delete old chunks for this file (re-index case)
  const oldChunkIds = rawDb.prepare("SELECT id FROM raw_chunks WHERE raw_id = ?").all(rawId) as { id: number }[];
  if (oldChunkIds.length > 0) {
    rawDb.exec("DELETE FROM raw_chunks WHERE raw_id = ?", [rawId] as any);
    for (const { id } of oldChunkIds) {
      try { rawDb.exec("DELETE FROM vec_raw WHERE chunk_id = ?", [id] as any); } catch {}
    }
  }

  const pendingEmbeds: { chunkId: number; content: string }[] = [];
  let chunksCreated = 0;

  // Summary chunk — the semantic anchor for the whole session
  const summaryText = parsed.summaryBody ?? parsed.summary ?? "";
  if (summaryText.trim()) {
    const chunkResult = rawDb.prepare(`
      INSERT INTO raw_chunks (raw_id, section_name, content, line_start, line_end, token_count, file_hash, created_at, updated_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).run(rawId, "summary", summaryText, 0, 0, Math.ceil(summaryText.length / 4), hash, ts, ts);
    const chunkId = Number(chunkResult.lastInsertRowid);
    pendingEmbeds.push({ chunkId, content: summaryText });
    chunksCreated++;
  }

  // Per-message chunks
  const messages = Array.isArray(parsed.messages) ? parsed.messages : [];
  for (let i = 0; i < messages.length; i++) {
    const msg = messages[i];
    const searchText = messageToSearchText(msg);
    if (!searchText.trim()) continue;

    const sectionName = messageSectionName(msg, i);
    // Store only searchText as content — FTS stays clean. Full message is recoverable
    // from the .json file using line_start (message index).
    const content = searchText;

    const chunkResult = rawDb.prepare(`
      INSERT INTO raw_chunks (raw_id, section_name, content, line_start, line_end, token_count, file_hash, created_at, updated_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).run(rawId, sectionName, content, i, i, Math.ceil(searchText.length / 4), hash, ts, ts);
    const chunkId = Number(chunkResult.lastInsertRowid);
    pendingEmbeds.push({ chunkId, content: searchText }); // embed the readable text, not the full JSON
    chunksCreated++;
  }

  // Update sync_meta
  rawDb.exec(`
    INSERT INTO sync_meta (source_path, file_hash, table_name, synced_at)
    VALUES (?, ?, 'raw_files', ?)
    ON CONFLICT(source_path) DO UPDATE SET
      file_hash=excluded.file_hash, synced_at=excluded.synced_at
  `.trim(), [sourcePath, hash, ts] as any);

  // Batch embed
  let chunksEmbedded = 0;

  if (!opts?.skipEmbed && pendingEmbeds.length > 0) {
    const texts = pendingEmbeds.map(p => p.content);
    const embedResult = await embedBatch(texts, "brain-raw-sync");
    const embedTs = now();

    for (let i = 0; i < pendingEmbeds.length; i++) {
      const embedding = embedResult.embeddings[i];
      if (embedding) {
        const buf = vectorToBuffer(embedding);
        rawDb.exec(
          "UPDATE raw_chunks SET embed_model = ?, embedded_at = ?, updated_at = ? WHERE id = ?",
          [EMBEDDING_CONFIG.model, embedTs, embedTs, pendingEmbeds[i].chunkId] as any
        );
        try {
          rawDb.exec(
            "INSERT INTO vec_raw(chunk_id, embedding) VALUES (?, ?)",
            [pendingEmbeds[i].chunkId, buf] as any
          );
        } catch {
          rawDb.exec(
            "UPDATE vec_raw SET embedding = ? WHERE chunk_id = ?",
            [buf, pendingEmbeds[i].chunkId] as any
          );
        }
        chunksEmbedded++;
      }
    }
  }

  return { rawId, chunksCreated, chunksEmbedded };
}

/**
 * Sync all raw files from vault/studio/memory/raw/ into brain.db.
 * Incremental: uses file_hash via sync_meta to skip unchanged files.
 *
 * @param opts.full - Rebuild all raw entries from scratch
 */
export async function syncRaw(opts?: { full?: boolean }): Promise<RawSyncResult> {
  const rawDb = getRawDb();
  const files = findRawFiles();

  if (opts?.full) {
    rawDb.exec("DELETE FROM raw_chunks");
    rawDb.exec("DELETE FROM vec_raw");
    rawDb.exec("DELETE FROM raw_files");
    rawDb.exec("DELETE FROM sync_meta WHERE table_name = 'raw_files'");
  }

  let filesProcessed = 0;
  let chunksCreated = 0;
  let chunksEmbedded = 0;
  let chunksFailed = 0;

  for (const filePath of files) {
    const content = readFileSync(filePath, "utf-8");
    const hash = hashFile(content);
    const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");

    // Skip unchanged files (incremental)
    const existing = rawDb.prepare("SELECT file_hash FROM sync_meta WHERE source_path = ?").get(sourcePath) as { file_hash: string } | null;
    if (existing && existing.file_hash === hash && !opts?.full) continue;

    try {
      const result = await insertRawFile(filePath);
      chunksCreated += result.chunksCreated;
      chunksEmbedded += result.chunksEmbedded;
      filesProcessed++;
    } catch (err) {
      // Skip files that fail to parse — may be legacy .md files or corrupt
      chunksFailed++;
    }
  }

  return { filesProcessed, chunksCreated, chunksEmbedded, chunksFailed };
}

