62	
63	  if (projectDirs.length === 0) {
64	    throw new Error(`No Claude project directories found for slug "${slug}" under ~/.claude*/projects/`);
65	  }
66	
67	  if (sessionId) {
68	    for (const dir of projectDirs) {
69	      const filePath = join(dir, `${sessionId}.jsonl`);
70	      if (existsSync(filePath)) {
