76	
77	  // Auto-detect: find most recently modified .jsonl across all dirs
78	  let latest: { path: string; mtime: number; sessionId: string } | null = null;
79	  for (const dir of projectDirs) {
80	    const entries = readdirSync(dir, { withFileTypes: true })
81	      .filter(e => e.isFile() && e.name.endsWith(".jsonl"));
82	    for (const entry of entries) {
83	      const filePath = join(dir, entry.name);
84	      const stat = statSync(filePath);
85	      if (!latest || stat.mtimeMs > latest.mtime) {
86	        latest = {
87	          path: filePath,
88	          mtime: stat.mtimeMs,
89	          sessionId: entry.name.replace(/\.jsonl$/, ""),
90	        };
91	      }
92	    }
93	  }
94	
95	  if (!latest) {
96	    throw new Error(`No JSONL session files found in any ~/.claude*/projects/${slug}/`);
97	  }
98	
99	  return { path: latest.path, sessionId: latest.sessionId };
100	}
101	
102	// ── JSONL Parser ───────────────────────────────────────────────────────────
103	
104	function truncateContent(content: string, max: number): string {
105	  if (content.length <= max) return content;
106	  return content.slice(0, max) + `...(truncated, ${content.length} chars)`;
107	}
108	
109	function processUserMessage(
110	  obj: any,
111	  toolNameMap: Map<string, string>
112	): CapturedMessage | CapturedMessage[] | null {
113	  const ts: string = obj.timestamp ?? "";
114	  const content = obj.message?.content;
115	
116	  if (typeof content === "string") {
117	    // Skip system-injected wrapped content
118	    if (
119	      /<local-command-stdout>/i.test(content) ||
120	      /<local-command-caveat>/i.test(content) ||
121	      /<command-name>/i.test(content)
122	    ) {
123	      return null;
124	    }
125	    if (!content.trim()) return null;
126	    return { ts, role: "user", type: "text", content };
127	  }
128	
129	  if (Array.isArray(content)) {
130	    const results: CapturedMessage[] = [];
131	    for (const block of content) {
132	      if (block.type === "text") {
133	        if (!block.text?.trim()) continue;
134	        results.push({ ts, role: "user", type: "text", content: block.text });
135	      } else if (block.type === "tool_result") {
136	        const toolName = toolNameMap.get(block.tool_use_id) ?? "unknown";
137	        const rawContent = typeof block.content === "string"
138	          ? block.content
139	          : JSON.stringify(block.content);
140	        results.push({
141	          ts,
142	          role: "tool_result",
143	          type: "text",
144	          tool: toolName,
145	          content: truncateContent(rawContent, 500),
146	        });
147	      }
148	    }
149	    return results.length > 0 ? results : null;
150	  }
151	
152	  return null;
153	}
154	
155	function processAssistantMessage(
156	  obj: any,
157	  toolNameMap: Map<string, string>
158	): CapturedMessage[] {
159	  const ts: string = obj.timestamp ?? "";
160	  const content = obj.message?.content;
161	  if (!Array.isArray(content)) return [];
162	
163	  const results: CapturedMessage[] = [];
164	  for (const block of content) {
165	    if (block.type === "text") {
166	      if (!block.text?.trim()) continue;
167	      results.push({ ts, role: "assistant", type: "text", content: block.text });
168	    } else if (block.type === "tool_use") {
169	      // Register this tool_use_id -> tool name for later tool_result lookup
170	      if (block.id && block.name) {
171	        toolNameMap.set(block.id, block.name);
172	      }
173	      results.push({
174	        ts,
175	        role: "assistant",
176	        type: "tool_use",
177	        tool: block.name,
178	        args: block.input ?? {},
179	      });
180	    } else if (block.type === "thinking") {
181	      if (!block.thinking?.trim()) continue;
182	      results.push({ ts, role: "assistant", type: "thinking", content: block.thinking });
183	    }
184	  }
185	  return results;
186	}
187	
188	function processJsonlLine(
189	  obj: any,
190	  toolNameMap: Map<string, string>
191	): CapturedMessage | CapturedMessage[] | null {
192	  switch (obj.type) {
193	    case "user":
194	      return processUserMessage(obj, toolNameMap);
195	    case "assistant":
196	      return processAssistantMessage(obj, toolNameMap);
197	    case "progress":
198	    case "file-history-snapshot":
199	    case "system":
200	    case "last-prompt":
201	      return null;
202	    default:
203	      return null;
204	  }
205	}
206	
207	function parseJsonlSession(jsonlPath: string): CapturedMessage[] {
208	  const content = readFileSync(jsonlPath, { encoding: "utf-8" });
209	  const lines = content.split(/\r?\n/).filter(l => l.trim() !== "");
210	  const messages: CapturedMessage[] = [];
211	  // Map tool_use_id -> tool name (populated as assistant messages are processed)
212	  const toolNameMap = new Map<string, string>();
213	
214	  for (const line of lines) {
215	    let obj: any;
216	    try {
217	      obj = JSON.parse(line);
218	    } catch {
219	      continue; // skip malformed lines
220	    }
221	
222	    const result = processJsonlLine(obj, toolNameMap);
223	    if (result === null) continue;
224	    if (Array.isArray(result)) {
225	      messages.push(...result);
226	    } else {
227	      messages.push(result);
228	    }
229	  }
230	
231	  return messages;
232	}
233	
234	// ── Core function ──────────────────────────────────────────────────────────
235	
236	async function runWriteRaw(args: WriteRawArgs): Promise<string> {
237	  const { path: jsonlPath, sessionId } = findSessionJsonl(args.session);
238	  const messages = parseJsonlSession(jsonlPath);
239	
240	  let summaryBody: string | undefined;
241	  if (args.summaryFile) {
242	    summaryBody = readFileSync(args.summaryFile, "utf-8");
243	  }
244	
245	  const result = writeRaw({
246	    agents: args.agents,
247	    skill: args.skill,
248	    tags: args.tags,
249	    summary: args.summary,
250	    summaryBody,
251	    sessionId,
252	    messages,
253	  });
254	
255	  let indexed = false;
256	  if (result.written) {
257	    initBrain();
258	    const indexResult = await insertRawFile(result.filePath);
259	    indexed = indexResult.chunksCreated > 0;
260	  }
261	
262	  return JSON.stringify({
263	    timestamp: result.timestamp,
264	    filePath: result.filePath,
265	    written: result.written,
266	    indexed,
267	    sessionId,
268	    messages: messages.length,
269	  });
270	}
271	
272	// ── Tool definition ────────────────────────────────────────────────────────
273	
274	export const toolDef: ToolDefinition = {
275	  name: "write-raw",
276	  description: "Write a raw context file from Claude Code JSONL session to memory/raw/ and index into brain.db",
277	  tags: ["memory"],
278	  inputSchema: z.object({
279	    agents: z.array(z.string()).describe("Agent names that participated"),
280	    skill: z.string().optional().describe("Skill name (e.g. /create-track)"),
281	    tags: z.array(z.string()).optional().describe("Topic tags"),
282	    summary: z.string().optional().describe("One-line summary for frontmatter"),
283	    summaryFile: z.string().optional().describe("Path to markdown file with full summary for # Summary section"),
284	    session: z.string().optional().describe("Session ID override (default: auto-detect most recent JSONL)"),
285	  }),
286	  execute: async (params) => {
287	    const output = await runWriteRaw(params as WriteRawArgs);
288	    return { content: [{ type: "text" as const, text: output }] };
289	  },
290	};
291	
292	// ── CLI ────────────────────────────────────────────────────────────────────
293	
294	if (import.meta.main) {
295	  const args = process.argv.slice(2);
296	
297	  function flagValue(name: string): string | undefined {
298	    const idx = args.indexOf(`--${name}`);
299	    if (idx < 0 || idx + 1 >= args.length) return undefined;
300	    return args[idx + 1];
301	  }
302	
303	  const agentsRaw = flagValue("agents");
304	
305	  if (!agentsRaw) {
306	    console.error("Usage: bun src/tools/write-raw.ts --agents freddie,mccall [--skill /create-track] [--tags jazz,test] [--summary '...'] [--summary-file out/session-summary.md] [--session {id}]");
307	    process.exit(1);
308	  }
309	
310	  // Check for removed --input flag and give a clear error
311	  if (args.includes("--input")) {
312	    console.error("[write-raw error] --input flag removed. Use --summary-file for a markdown summary, or omit for JSONL auto-capture.");
313	    process.exit(1);
314	  }
315	
316	  const agents = agentsRaw.split(",").map(s => s.trim());
317	  const skill = flagValue("skill");
318	  const tags = flagValue("tags")?.split(",").map(s => s.trim());
319	  const summary = flagValue("summary");
320	  const summaryFile = flagValue("summary-file");
321	  const session = flagValue("session");
322	
323	  try {
324	    const output = await runWriteRaw({ agents, skill, tags, summary, summaryFile, session });
325	    console.log(output);
326	  } catch (err: any) {
327	    console.error(`[write-raw error] ${err.message}`);
328	    process.exit(1);
329	  }
330	}
