#!/usr/bin/env bun
/**
 * write-raw.ts — CLI tool for writing raw context files from Claude Code JSONL sessions
 *
 * Dual-mode: CLI (`bun src/tools/write-raw.ts --agents freddie ...`) or native tool via registry.
 * Reads JSONL session files from ~/.claude/projects/{project-slug}/, writes a raw context file
 * to memory/raw/, indexes into brain.db, outputs JSON with timestamp.
 *
 * Options:
 *   --agents        Comma-separated agent names (required)
 *   --skill         Skill name (e.g. /create-track)
 *   --tags          Comma-separated tags
 *   --summary       One-line summary for frontmatter
 *   --summary-file  Path to markdown file with full summary for # Summary section
 *   --session       Session ID override (default: auto-detect most recent JSONL)
 */

import { readFileSync, readdirSync, statSync, existsSync } from "fs";
import { join, basename } from "path";
import { homedir } from "os";
import { writeRaw, type CapturedMessage } from "../libs/raw.js";
import { initBrain, insertRawFile } from "../libs/brain/index.js";
import { z } from "zod";
import type { ToolDefinition } from "../registry/types.js";

// ── Types ──────────────────────────────────────────────────────────────────

interface WriteRawArgs {
  agents: string[];
  skill?: string;
  tags?: string[];
  summary?: string;
  summaryFile?: string;
  session?: string;
}

// ── JSONL Resolution ───────────────────────────────────────────────────────

function buildProjectSlug(cwd: string): string {
  // Claude Code slug format: "d:\PROJECTS\freddie-ai" -> "d--PROJECTS-freddie-ai"
  // Rules: lowercase drive letter, ":\\" becomes "--", remaining separators become "-"
  return cwd
    .replace(/^([A-Za-z]):\\/, (_, d) => d.toLowerCase() + "--")  // drive letter + first \
    .replace(/[\\\/]/g, "-");                                       // remaining separators
}

function findSessionJsonl(sessionId?: string): { path: string; sessionId: string } {
  const home = homedir();
  const slug = buildProjectSlug(process.cwd());

  // Collect all ~/.claude*/projects/{slug}/ directories
