  for (const entry of homeEntries) {
    if (entry.isDirectory() && /^\.claude/.test(entry.name)) {
      const candidate = join(home, entry.name, "projects", slug);
      if (existsSync(candidate)) {
        projectDirs.push(candidate);
      }
    }
  }

  if (projectDirs.length === 0) {
    throw new Error(`No Claude project directories found for slug "${slug}" under ~/.claude*/projects/`);
  }

  if (sessionId) {
    for (const dir of projectDirs) {
      const filePath = join(dir, `${sessionId}.jsonl`);
      if (existsSync(filePath)) {
        return { path: filePath, sessionId };
      }
    }
    throw new Error(`Session file "${sessionId}.jsonl" not found in any ~/.claude*/projects/${slug}/`);
  }

  // Auto-detect: find most recently modified .jsonl across all dirs
  let latest: { path: string; mtime: number; sessionId: string } | null = null;
  for (const dir of projectDirs) {
    const entries = readdirSync(dir, { withFileTypes: true })
      .filter(e => e.isFile() && e.name.endsWith(".jsonl"));
    for (const entry of entries) {
      const filePath = join(dir, entry.name);
      const stat = statSync(filePath);
      if (!latest || stat.mtimeMs > latest.mtime) {
        latest = {
          path: filePath,
          mtime: stat.mtimeMs,
          sessionId: entry.name.replace(/\.jsonl$/, ""),
        };
      }
    }
  }

  if (!latest) {
    throw new Error(`No JSONL session files found in any ~/.claude*/projects/${slug}/`);
  }

  return { path: latest.path, sessionId: latest.sessionId };
}

// ── JSONL Parser ───────────────────────────────────────────────────────────

function truncateContent(content: string, max: number): string {
  if (content.length <= max) return content;
  return content.slice(0, max) + `...(truncated, ${content.length} chars)`;
}

function processUserMessage(
  obj: any,
  toolNameMap: Map<string, string>
): CapturedMessage | CapturedMessage[] | null {
  const ts: string = obj.timestamp ?? "";
  const content = obj.message?.content;

  if (typeof content === "string") {
    // Skip system-injected wrapped content
    if (
      /<local-command-stdout>/i.test(content) ||
      /<local-command-caveat>/i.test(content) ||
      /<command-name>/i.test(content)
    ) {
      return null;
    }
    if (!content.trim()) return null;
    return { ts, role: "user", type: "text", content };
  }

  if (Array.isArray(content)) {
    const results: CapturedMessage[] = [];
    for (const block of content) {
      if (block.type === "text") {
        if (!block.text?.trim()) continue;
        results.push({ ts, role: "user", type: "text", content: block.text });
      } else if (block.type === "tool_result") {
        const toolName = toolNameMap.get(block.tool_use_id) ?? "unknown";
        const rawContent = typeof block.content === "string"
          ? block.content
          : JSON.stringify(block.content);
        results.push({
          ts,
          role: "tool_result",
          type: "text",
          tool: toolName,
          content: truncateContent(rawContent, 500),
        });
      }
    }
    return results.length > 0 ? results : null;
  }

  return null;
}

function processAssistantMessage(
  obj: any,
  toolNameMap: Map<string, string>
): CapturedMessage[] {
  const ts: string = obj.timestamp ?? "";
  const content = obj.message?.content;
  if (!Array.isArray(content)) return [];

  const results: CapturedMessage[] = [];
  for (const block of content) {
    if (block.type === "text") {
      if (!block.text?.trim()) continue;
      results.push({ ts, role: "assistant", type: "text", content: block.text });
    } else if (block.type === "tool_use") {
      // Register this tool_use_id -> tool name for later tool_result lookup
      if (block.id && block.name) {
        toolNameMap.set(block.id, block.name);
      }
      results.push({
        ts,
        role: "assistant",
        type: "tool_use",
        tool: block.name,
        args: block.input ?? {},
      });
    } else if (block.type === "thinking") {
      if (!block.thinking?.trim()) continue;
      results.push({ ts, role: "assistant", type: "thinking", content: block.thinking });
    }
  }
  return results;
}

function processJsonlLine(
  obj: any,
  toolNameMap: Map<string, string>
): CapturedMessage | CapturedMessage[] | null {
  switch (obj.type) {
    case "user":
      return processUserMessage(obj, toolNameMap);
    case "assistant":
      return processAssistantMessage(obj, toolNameMap);
    case "progress":
    case "file-history-snapshot":
    case "system":
    case "last-prompt":
      return null;
    default:
      return null;
  }
}

function parseJsonlSession(jsonlPath: string): CapturedMessage[] {
  const content = readFileSync(jsonlPath, { encoding: "utf-8" });
  const lines = content.split(/\r?\n/).filter(l => l.trim() !== "");
  const messages: CapturedMessage[] = [];
  // Map tool_use_id -> tool name (populated as assistant messages are processed)
  const toolNameMap = new Map<string, string>();

  for (const line of lines) {
    let obj: any;
    try {
      obj = JSON.parse(line);
    } catch {
      continue; // skip malformed lines
    }

    const result = processJsonlLine(obj, toolNameMap);
    if (result === null) continue;
    if (Array.isArray(result)) {
      messages.push(...result);
    } else {
      messages.push(result);
    }
  }

  return messages;
}

// ── Core function ──────────────────────────────────────────────────────────

async function runWriteRaw(args: WriteRawArgs): Promise<string> {
  const { path: jsonlPath, sessionId } = findSessionJsonl(args.session);
  const messages = parseJsonlSession(jsonlPath);

  let summaryBody: string | undefined;
  if (args.summaryFile) {
    summaryBody = readFileSync(args.summaryFile, "utf-8");
  }

  const result = writeRaw({
    agents: args.agents,
    skill: args.skill,
    tags: args.tags,
    summary: args.summary,
    summaryBody,
    sessionId,
    messages,
  });

  let indexed = false;
  if (result.written) {
    initBrain();
    const indexResult = await insertRawFile(result.filePath);
    indexed = indexResult.chunksCreated > 0;
  }

  return JSON.stringify({
    timestamp: result.timestamp,
    filePath: result.filePath,
    written: result.written,
    indexed,
    sessionId,
    messages: messages.length,
  });
}

// ── Tool definition ────────────────────────────────────────────────────────

export const toolDef: ToolDefinition = {
  name: "write-raw",
  description: "Write a raw context file from Claude Code JSONL session to memory/raw/ and index into brain.db",
  tags: ["memory"],
  inputSchema: z.object({
    agents: z.array(z.string()).describe("Agent names that participated"),
    skill: z.string().optional().describe("Skill name (e.g. /create-track)"),
    tags: z.array(z.string()).optional().describe("Topic tags"),
    summary: z.string().optional().describe("One-line summary for frontmatter"),
    summaryFile: z.string().optional().describe("Path to markdown file with full summary for # Summary section"),
    session: z.string().optional().describe("Session ID override (default: auto-detect most recent JSONL)"),
  }),
  execute: async (params) => {
    const output = await runWriteRaw(params as WriteRawArgs);
    return { content: [{ type: "text" as const, text: output }] };
  },
};

// ── CLI ────────────────────────────────────────────────────────────────────

if (import.meta.main) {
  const args = process.argv.slice(2);

  function flagValue(name: string): string | undefined {
    const idx = args.indexOf(`--${name}`);
    if (idx < 0 || idx + 1 >= args.length) return undefined;
    return args[idx + 1];
  }

  const agentsRaw = flagValue("agents");

  if (!agentsRaw) {
    console.error("Usage: bun src/tools/write-raw.ts --agents freddie,mccall [--skill /create-track] [--tags jazz,test] [--summary '...'] [--summary-file out/session-summary.md] [--session {id}]");
    process.exit(1);
  }

  // Check for removed --input flag and give a clear error
  if (args.includes("--input")) {
    console.error("[write-raw error] --input flag removed. Use --summary-file for a markdown summary, or omit for JSONL auto-capture.");
    process.exit(1);
  }

  const agents = agentsRaw.split(",").map(s => s.trim());
  const skill = flagValue("skill");
  const tags = flagValue("tags")?.split(",").map(s => s.trim());
  const summary = flagValue("summary");
  const summaryFile = flagValue("summary-file");
  const session = flagValue("session");

  try {
    const output = await runWriteRaw({ agents, skill, tags, summary, summaryFile, session });
    console.log(output);
  } catch (err: any) {
    console.error(`[write-raw error] ${err.message}`);
    process.exit(1);
  }
}

