2	/**
3	 * capture-raw.ts — Auto-capture Claude Code transcripts to memory/raw/
4	 *
5	 * Three modes:
6	 *   --post-tool    PostToolUse: append raw stdin line to {session_id}.jsonl (hot path, <50ms)
7	 *   --pre-compact  PreCompact: copy full transcript to {session_id}.jsonl
8	 *   --stop         Stop: copy transcript, write .md with frontmatter, index to brain.db
9	 */
10	
11	import { appendFileSync, copyFileSync, writeFileSync, mkdirSync, readFileSync, existsSync } from "fs";
12	import { join } from "path";
13	import { fromRoot } from "../../src/libs/paths.js";
14	
15	const RAW_DIR = fromRoot("vault", "studio", "memory", "raw");
16	mkdirSync(RAW_DIR, { recursive: true });
17	
18	const mode = process.argv[2]; // "--post-tool" | "--pre-compact" | "--stop"
19	
20	// --------------------------------------------------------------------------
21	// PostToolUse — hot path, must complete under 50ms
22	// --------------------------------------------------------------------------
