#!/usr/bin/env bun
/**
 * capture-raw.ts — Auto-capture Claude Code transcripts to memory/raw/
 *
 * Three modes:
 *   --post-tool    PostToolUse: append raw stdin line to {session_id}.jsonl (hot path, <50ms)
 *   --pre-compact  PreCompact: copy full transcript to {session_id}.jsonl
 *   --stop         Stop: copy transcript, write .md with frontmatter, index to brain.db
 */

import { appendFileSync, copyFileSync, writeFileSync, mkdirSync, readFileSync, existsSync } from "fs";
import { join } from "path";
import { fromRoot } from "../../src/libs/paths.js";

const RAW_DIR = fromRoot("vault", "studio", "memory", "raw");
mkdirSync(RAW_DIR, { recursive: true });

const mode = process.argv[2]; // "--post-tool" | "--pre-compact" | "--stop"

// --------------------------------------------------------------------------
// PostToolUse — hot path, must complete under 50ms
// --------------------------------------------------------------------------
if (mode === "--post-tool") {
  try {
    const raw = await Bun.stdin.text();
    const parsed = JSON.parse(raw) as { session_id: string };
    const { session_id } = parsed;
    if (!session_id) process.exit(0);
    appendFileSync(join(RAW_DIR, session_id + ".jsonl"), raw + "\n");
  } catch {
    // Never block Claude Code
  }
  process.exit(0);
}

// --------------------------------------------------------------------------
// PreCompact — copy full transcript, overwriting partial PostToolUse appends
// --------------------------------------------------------------------------
if (mode === "--pre-compact") {
  try {
    const raw = await Bun.stdin.text();
    const parsed = JSON.parse(raw) as { session_id: string; transcript_path: string };
    const { session_id, transcript_path } = parsed;
    if (!session_id || !transcript_path) process.exit(0);
    if (!existsSync(transcript_path)) process.exit(0);
    copyFileSync(transcript_path, join(RAW_DIR, session_id + ".jsonl"));
  } catch {
    // Never block Claude Code
  }
  process.exit(0);
}

// --------------------------------------------------------------------------
// Stop — heavy path, runs once at session end
// --------------------------------------------------------------------------
if (mode === "--stop") {
  try {
    const raw = await Bun.stdin.text();
    const parsed = JSON.parse(raw) as {
      session_id: string;
      transcript_path: string;
      last_assistant_message: string;
    };
    const { session_id, transcript_path, last_assistant_message } = parsed;
    if (!session_id) process.exit(0);

    // Copy transcript (overwrites PostToolUse partial appends)
    if (transcript_path && existsSync(transcript_path)) {
      copyFileSync(transcript_path, join(RAW_DIR, session_id + ".jsonl"));
    }

    const jsonlPath = join(RAW_DIR, session_id + ".jsonl");
    const mdPath = join(RAW_DIR, session_id + ".md");

    // Parse JSONL for metadata
    const toolCounts = countToolsFromJsonl(jsonlPath);
    const date = extractDateFromJsonl(jsonlPath);
    const ts = Math.floor(Date.now() / 1000);

    // Build frontmatter
    const toolsJson = JSON.stringify(toolCounts.map(t => ({ name: t.name, count: t.count })));

    const summary = last_assistant_message?.trim() || "Session ended without summary.";

    const md = [
      "---",
      `ts: ${ts}`,
      `date: ${date}`,
      `session_id: ${session_id}`,
      `agents: ["freddie"]`,
      `skill: null`,
      `tags: [auto-captured]`,
      `tools_used: ${toolsYaml}`,
      `format: jsonl`,
      "---",
      "",
      `# Session ${session_id}`,
      "",
      summary,
    ].join("\n");

    writeFileSync(mdPath, md, "utf-8");

    // Dynamic import — only in Stop path so PostToolUse is never slowed
    try {
      const { initBrain } = await import("../../src/libs/brain/index.js");
      const { insertRawJsonl } = await import("../../src/libs/brain/raw.js");
      initBrain();
      await insertRawJsonl(jsonlPath, mdPath);
    } catch (err) {
      process.stderr.write(`[capture-raw] brain index unavailable: ${String(err)}\n`);
    }
  } catch (err) {
    process.stderr.write(`[capture-raw] stop error: ${String(err)}\n`);
  }
  process.exit(0);
}

// Unknown mode — exit cleanly
process.exit(0);

